checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`sensitive cookie name expression S`) {
      OR {
        AND {
          (`S is a compile-time constant string expression`),
          (`S's string value matches regex "(?i).*(auth|session|token|key|credential).*"`),
          NOT { (`S's string value matches regex "(?i).*(csrf).*"`) }
        },
        (`S is a sensitive cookie name expression`)
      }
    },
    EXISTS (`cookie-setting sink call C`) {
      OR {
        AND {
          (`C is a method call`),
          OR {
            (`C's method is an addHeader method on HttpServletResponse`),
            (`C's method is a setHeader method on HttpServletResponse`)
          },
          (`C's first argument is a compile-time constant string with value "set-cookie" (case-insensitive)`),
          NOT {
            EXISTS (`taint flow path F1`) {
              AND {
                EXISTS (`source node N1 containing string "httponly" (case-insensitive substring)`) {
                  (`N1's expression is a compile-time constant string`)
                },
                (`taint flows from N1 to the second argument of C`)
              }
            }
          }
        },
        AND {
          (`C is a method call to addCookie on HttpServletResponse`),
          NOT {
            EXISTS (`taint flow path F2`) {
              AND {
                EXISTS (`cookie object modification M`) {
                  OR {
                    AND {
                      (`M is a method call to setHttpOnly`),
                      (`M's first argument is a boolean expression that may be true`)
                    },
                    AND {
                      (`M is a method call to setMaxAge`),
                      (`M's first argument is an integer literal with value 0`)
                    }
                  }
                },
                (`taint flows from the qualifier of M to the first argument of C`)
              }
            }
          }
        }
      }
    },
    (`taint flows from S to C through path P`),
    NOT {
      EXISTS (`barrier node B on path P`) {
        AND {
          (`B's expression is a constructor call to NewCookie`),
          OR {
            AND {
              (`the constructor has 6 arguments`),
              (`the 6th argument is a boolean expression that may be true`)
            },
            AND {
              (`the constructor has 8 arguments`),
              (`the 7th argument's type is boolean`),
              (`the 8th argument is a boolean expression that may be true`)
            },
            AND {
              (`the constructor has 10 arguments`),
              (`the 10th argument is a boolean expression that may be true`)
            }
          }
        }
      }
    },
    EXISTS (`additional flow step pair (pred, succ) on path P`) {
      OR {
        AND {
          (`pred's expression is an argument to a Cookie constructor call`),
          (`succ's expression is that Cookie constructor call`)
        },
        AND {
          (`pred's expression is the qualifier of a toString method call on a Cookie object`),
          (`succ's expression is that toString method call`)
        }
      }
    }
  }
}
